const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const A = input.slice(idx, idx + N); idx += N;
  const B = input.slice(idx, idx + N); idx += N;
  A.sort((x, y) => y - x); // descending
  B.sort((x, y) => x - y); // ascending
  output.push(A.join(' '));
  output.push(B.join(' '));
}
